import React, { useState } from 'react';

function SearchComponent({ entityName, entityIdKey, onSearch, onEdit, onDelete }) {
  const [searchId, setSearchId] = useState('');
  const [searchResult, setSearchResult] = useState(null);
  const [searchError, setSearchError] = useState(null);

  const handleSearchClick = async () => {
    if (!searchId) {
      setSearchError(`Please enter a ${entityName} ID.`);
      setSearchResult(null);
      return;
    }
    setSearchError(null);
    try {
      const record = await onSearch(searchId);
      setSearchResult(record);
      setSearchError(null);
    } catch (err) {
      setSearchResult(null);
      setSearchError(err.message || 'Record not found.');
    }
  };

  const searchContainerStyles = {
    background: 'rgba(255, 255, 255, 0.95)',
    backdropFilter: 'blur(10px)',
    borderRadius: '24px',
    padding: '40px',
    margin: '30px 0',
    boxShadow: '0 12px 45px rgba(17, 153, 142, 0.15)',
    border: '1px solid rgba(17, 153, 142, 0.15)',
  };

  const headerStyles = {
    fontSize: '1.7rem',
    fontWeight: '800',
    background: 'linear-gradient(135deg, #11998e 0%, #38ef7d 100%)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    textAlign: 'center',
    marginBottom: '25px',
    letterSpacing: '0.5px',
  };

  const searchInputStyles = {
    padding: '14px 18px',
    borderRadius: '14px',
    border: '2px solid rgba(17, 153, 142, 0.25)',
    fontSize: '1rem',
    width: '240px',
    transition: 'all 0.3s ease',
    background: 'rgba(255, 255, 255, 0.9)',
    fontFamily: 'inherit',
    fontWeight: '500',
  };

  const searchButtonStyles = {
    background: 'linear-gradient(135deg, #11998e 0%, #38ef7d 100%)',
    color: 'white',
    border: 'none',
    padding: '14px 32px',
    borderRadius: '14px',
    fontSize: '1rem',
    fontWeight: '600',
    cursor: 'pointer',
    transition: 'all 0.3s ease',
    boxShadow: '0 5px 18px rgba(17, 153, 142, 0.35)',
    letterSpacing: '0.5px',
  };

  const errorStyles = {
    background: 'linear-gradient(135deg, #e74c3c, #c0392b)',
    color: 'white',
    padding: '16px 25px',
    borderRadius: '14px',
    marginTop: '25px',
    boxShadow: '0 6px 20px rgba(231, 76, 60, 0.4)',
    border: 'none',
    fontSize: '1rem',
    fontWeight: '600',
    animation: 'shake 0.5s ease',
    textAlign: 'center',
  };

  const resultContainerStyles = {
    marginTop: '30px',
    borderTop: '2px dashed rgba(17, 153, 142, 0.2)',
    paddingTop: '25px',
  };

  const resultHeaderStyles = {
    fontSize: '1.3rem',
    fontWeight: '700',
    color: '#222',
    marginBottom: '20px',
    textAlign: 'center',
  };

  const resultCardStyles = {
    background: 'rgba(255, 255, 255, 0.95)',
    padding: '25px',
    borderRadius: '16px',
    boxShadow: '0 6px 18px rgba(0,0,0,0.08)',
    border: '1px solid rgba(17, 153, 142, 0.15)',
    marginBottom: '20px',
  };

  const fieldRowStyles = {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '8px 0',
    borderBottom: '1px solid rgba(0,0,0,0.07)',
  };

  const fieldLabelStyles = {
    fontWeight: '600',
    color: '#444',
    fontSize: '0.95rem',
  };

  const fieldValueStyles = {
    color: '#222',
    fontSize: '0.95rem',
    textAlign: 'right',
  };

  const actionButtonContainerStyles = {
    display: 'flex',
    gap: '20px',
    justifyContent: 'center',
    marginTop: '25px',
  };

  const editButtonStyles = {
    background: 'linear-gradient(135deg, #11998e 0%, #38ef7d 100%)',
    color: 'white',
    border: 'none',
    padding: '12px 26px',
    borderRadius: '12px',
    fontSize: '0.95rem',
    fontWeight: '600',
    cursor: 'pointer',
    transition: 'all 0.3s ease',
    boxShadow: '0 4px 15px rgba(17, 153, 142, 0.3)',
    letterSpacing: '0.3px',
  };

  const deleteButtonStyles = {
    background: 'linear-gradient(135deg, #e74c3c, #c0392b)',
    color: 'white',
    border: 'none',
    padding: '12px 26px',
    borderRadius: '12px',
    fontSize: '0.95rem',
    fontWeight: '600',
    cursor: 'pointer',
    transition: 'all 0.3s ease',
    boxShadow: '0 4px 15px rgba(231, 76, 60, 0.3)',
    letterSpacing: '0.3px',
  };

  return (
    <>
      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-5px); }
          75% { transform: translateX(5px); }
        }
      `}</style>

      <div style={searchContainerStyles}>
        <h3 style={headerStyles}>🔍 Search {entityName} by ID</h3>

        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', flexWrap: 'wrap', gap: '12px' }}>
          <input
            type="number"
            value={searchId}
            onChange={(e) => setSearchId(e.target.value)}
            placeholder={`Enter ${entityName} ID`}
            style={searchInputStyles}
            onFocus={(e) => {
              e.target.style.borderColor = '#11998e';
              e.target.style.boxShadow = '0 0 0 3px rgba(17, 153, 142, 0.15)';
            }}
            onBlur={(e) => {
              e.target.style.borderColor = 'rgba(17, 153, 142, 0.25)';
              e.target.style.boxShadow = 'none';
            }}
          />
          <button
            onClick={handleSearchClick}
            style={searchButtonStyles}
            onMouseEnter={(e) => {
              e.target.style.transform = 'translateY(-2px) scale(1.05)';
              e.target.style.boxShadow = '0 10px 28px rgba(17, 153, 142, 0.45)';
            }}
            onMouseLeave={(e) => {
              e.target.style.transform = 'translateY(0) scale(1)';
              e.target.style.boxShadow = '0 5px 18px rgba(17, 153, 142, 0.35)';
            }}
          >
            🔍 Search
          </button>
        </div>

        {searchError && <div style={errorStyles}>⚠️ {searchError}</div>}

        {searchResult && (
          <div style={resultContainerStyles}>
            <h4 style={resultHeaderStyles}>
              ✅ Search Result: {entityName} ID {searchResult[entityIdKey]}
            </h4>
            <div style={resultCardStyles}>
              {Object.entries(searchResult).map(([key, value]) => {
                if (key === entityIdKey) return null;
                const displayKey = key.replace(/_/g, ' ').replace(/\b\w/g, (l) => l.toUpperCase());
                const displayValue = value === null || value === undefined ? 'N/A' : value;
                return (
                  <div key={key} style={fieldRowStyles}>
                    <span style={fieldLabelStyles}>{displayKey}:</span>
                    <span style={fieldValueStyles}>{displayValue}</span>
                  </div>
                );
              })}
            </div>
            <div style={actionButtonContainerStyles}>
              <button
                onClick={() => onEdit(searchResult)}
                style={editButtonStyles}
                onMouseEnter={(e) => {
                  e.target.style.transform = 'scale(1.05)';
                  e.target.style.boxShadow = '0 8px 22px rgba(17, 153, 142, 0.4)';
                }}
                onMouseLeave={(e) => {
                  e.target.style.transform = 'scale(1)';
                  e.target.style.boxShadow = '0 4px 15px rgba(17, 153, 142, 0.3)';
                }}
              >
                ✏️ Edit Record
              </button>
              <button
                onClick={() => onDelete(searchResult[entityIdKey])}
                style={deleteButtonStyles}
                onMouseEnter={(e) => {
                  e.target.style.transform = 'scale(1.05)';
                  e.target.style.boxShadow = '0 8px 22px rgba(231, 76, 60, 0.4)';
                }}
                onMouseLeave={(e) => {
                  e.target.style.transform = 'scale(1)';
                  e.target.style.boxShadow = '0 4px 15px rgba(231, 76, 60, 0.3)';
                }}
              >
                🗑️ Delete Record
              </button>
            </div>
          </div>
        )}
      </div>
    </>
  );
}

export default SearchComponent;
